#include<iostream>
#define ls p<<1
#define rs p<<1|1
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
CI T=400001,E=100001;
struct node
{
	int l,r,min;
}tr[T];
int e[E],sum=0,k,n;
void pushup(int p)
{
	tr[p].min=min(tr[ls].min,tr[rs].min);
}
void build(int p,int l,int r)
{
	tr[p]={l,r,inf};
	if(l==r)
	{
		return;
	}
	int m=l+r>>1;
	build(ls,l,m);
	build(rs,m+1,r);
}
void update(int p,int x,int k)
{
	if(tr[p].l==tr[p].r)
	{
		tr[p].min=k;
		return;
	}
	int m=tr[p].l+tr[p].r>>1;
	if(x<=m)
	{
		update(ls,x,k);
	}
	else
	{
		update(rs,x,k);
	}
	pushup(p);
}
int query(int p,int x,int y)
{
	if(tr[p].l>=x&&tr[p].r<=y)
	{
		return tr[p].min;
	}
	int m=tr[p].l+tr[p].r>>1,s=inf;
	if(x<=m)
	{
		s=query(ls,x,y);
	}
	if(y>m)
	{
		s=min(s,query(rs,x,y));
	}
	return s;
}
signed main()
{
	IOS
	cin>>n>>k;
	FOR(i,1,n)
	{
		cin>>e[i];
		sum+=e[i];
	}
	build(1,0,n+1);
	update(1,0,0);
	FOR(i,1,n+1)
	{
		int k1=query(1,max(i-k-1,0ll),i-1);
		update(1,i,k1+e[i]);
	}
	cout<<sum-query(1,n+1,n+1);
	return 0;
}
